  window.initStockDashboardModule=function(force){injectStyle();var seed=CSV6.dashboard||readClientSnapshot();if(seed){applySharedSnapshot(seed);renderDashboardFromState();setFreshness('sdDataFreshness','stale',clientCacheMeta.source==='bundled snapshot'?'Preloaded data':'Cached data');}else{loading('sdKpiGrid','กำลังเตรียมข้อมูล Stock Inventory...');setFreshness('sdDataFreshness','syncing','Loading');}if(!shouldRefresh(force)&&seed)return Promise.resolve(seed);setFreshness('sdDataFreshness','syncing','Syncing in background');return refreshSharedSnapshot(!!force).then(function(p){renderDashboardFromState();setFreshness('sdDataFreshness','live','Updated '+new Date().toLocaleTimeString('th-TH',{hour:'2-digit',minute:'2-digit'}));return p;}).catch(function(e){setFreshness('sdDataFreshness','stale',seed?'Using cached data':'Load failed');if(!seed)inlineError('sdKpiGrid','Stock Dashboard Error',e,'initStockDashboardModule(true)');else toast('warning','ใช้ข้อมูลที่บันทึกไว้ เนื่องจาก Sync ไม่สำเร็จ');return seed;});};
  window.sd_fillFilters=function(){var p=CSV6.dashboard;if(!p)return;fillSelect('sdBrand',p.filters.brands,'ทุกแบรนด์');sd_fillModelOptions();fillSelect('sdStatus',STATUS,'ทุกสถานะ');fillSelect('sdLocation',p.filters.locations,'ทุกสถานที่');};
  function sd_fillModelOptions(){var p=CSV6.dashboard;if(!p)return;var b=val('sdBrand','all');var models=p.filters.models.filter(function(m){if(b==='all')return true;return (b==='BYOND'&&m==='Sunfusion 2')||(b==='B.Braun'&&m!=='Sunfusion 2');});fillSelect('sdModel',models,'ทุกโมเดล');}
  window.sd_onBrandChange=function(){sd_fillModelOptions();sd_renderFiltered();};
  function dashboardRows(){var p=CSV6.dashboard;if(!p)return[];var q=val('sdSearch','').trim().toLowerCase(),b=val('sdBrand','all'),m=val('sdModel','all'),s=val('sdStatus','all'),l=val('sdLocation','all');return p.devices.filter(function(d){var hay=[d.idCode,d.sn,d.brand,d.model,d.location,d.status,d.borrower,d.actionRequired].join(' ').toLowerCase();return(!q||hay.indexOf(q)>=0)&&(b==='all'||d.brand===b)&&(m==='all'||d.model===m)&&(s==='all'||d.status===s)&&(l==='all'||d.location===l);});}
  window.sd_renderFiltered=function(){var rows=dashboardRows();renderModelCards(rows);renderDashboardKpis(rows);renderTopLocations(rows);renderContracts(rows);var alerts=rows.filter(function(d){return d.status==='ใช้งานไม่ได้'||d.status==='ไม่พบในรายการ'||d.isOverdue;});text('sdAlertHeaderCount',alerts.length);text('sdAlertCount',alerts.length);CSV6.alerts=alerts;clearTimeout(CSV6.chartTimer);CSV6.chartTimer=setTimeout(function(){try{renderDashboardCharts(rows);}catch(e){console.warn('[Stock chart]',e);}},80);};
  window.sd_renderAll=window.sd_renderFiltered;
  function renderModelCards(rows){html('sdModelCards',MODELS.map(function(x){var r=rows.filter(function(d){return d.brand===x.brand&&d.model===x.model;}),c=countStatus(r);return '<div class="sp-model-card" style="--tone:'+x.color+'"><div class="sp-model-icon" style="background:'+x.bg+'"><i class="fas fa-microchip" style="color:'+x.color+'"></i></div><div class="sp-model-brand">'+esc(x.brand)+'</div><div class="sp-model-label">'+esc(x.model)+'</div><div class="sp-model-num" style="color:'+x.color+'">'+r.length+'</div><div class="csv5-model-status"><span>พร้อมส่ง <b>'+c['พร้อมส่ง']+'</b></span><span>รอสอบเทียบ <b>'+c['รอสอบเทียบ']+'</b></span><span>เช่ายืม <b>'+c['เช่ายืม']+'</b></span></div></div>';}).join(''));}
  function renderDashboardKpis(rows){var c=countStatus(rows);var items=[['อุปกรณ์ทั้งหมด',rows.length,'fa-boxes-stacked','#2563eb','#dbeafe'],['พร้อมส่ง',c['พร้อมส่ง'],META['พร้อมส่ง'].icon,META['พร้อมส่ง'].color,META['พร้อมส่ง'].bg],['รอสอบเทียบ',c['รอสอบเทียบ'],META['รอสอบเทียบ'].icon,META['รอสอบเทียบ'].color,META['รอสอบเทียบ'].bg],['เช่ายืม',c['เช่ายืม'],META['เช่ายืม'].icon,META['เช่ายืม'].color,META['เช่ายืม'].bg],['ใช้งานไม่ได้',c['ใช้งานไม่ได้'],META['ใช้งานไม่ได้'].icon,META['ใช้งานไม่ได้'].color,META['ใช้งานไม่ได้'].bg],['ไม่พบในรายการ',c['ไม่พบในรายการ'],META['ไม่พบในรายการ'].icon,META['ไม่พบในรายการ'].color,META['ไม่พบในรายการ'].bg]];html('sdKpiGrid',items.map(function(i){return '<div class="sp-kpi" style="--tone:'+i[3]+'"><div class="ico" style="background:'+i[4]+'"><i class="fas '+i[2]+'" style="color:'+i[3]+'"></i></div><div class="label">'+esc(i[0])+'</div><div class="val" style="color:'+i[3]+'">'+i[1]+'</div></div>';}).join(''));}
  function destroyChart(k){if(CSV6.charts[k]){try{CSV6.charts[k].destroy();}catch(e){}CSV6.charts[k]=null;}}
  function renderDashboardCharts(rows){if(typeof Chart==='undefined')return;var c=countStatus(rows),labels=STATUS.slice(),colors=labels.map(function(s){return META[s].color;});destroyChart('status');destroyChart('model');destroyChart('brand');var statusCanvas=document.getElementById('sdStatusChart');if(statusCanvas)CSV6.charts.status=new Chart(statusCanvas,{type:'doughnut',data:{labels:labels,datasets:[{data:labels.map(function(s){return c[s];}),backgroundColor:colors,borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,cutout:'65%',plugins:{legend:{position:'bottom'}}}});var mc=MODELS.map(function(x){var r=rows.filter(function(d){return d.brand===x.brand&&d.model===x.model;});return{label:x.model,c:countStatus(r)};});var modelCanvas=document.getElementById('sdModelStatusChart');if(modelCanvas)CSV6.charts.model=new Chart(modelCanvas,{type:'bar',data:{labels:mc.map(function(x){return x.label;}),datasets:STATUS.map(function(s){return{label:s,data:mc.map(function(x){return x.c[s];}),backgroundColor:META[s].color,borderRadius:5};})},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom'}},scales:{x:{stacked:true},y:{stacked:true,beginAtZero:true}}}});var brands=['B.Braun','BYOND'],brandCanvas=document.getElementById('sdBrandChart');if(brandCanvas)CSV6.charts.brand=new Chart(brandCanvas,{type:'bar',data:{labels:brands,datasets:[{label:'จำนวนอุปกรณ์',data:brands.map(function(b){return rows.filter(function(d){return d.brand===b;}).length;}),backgroundColor:['#2563eb','#06b6d4'],borderRadius:8}]},options:{responsive:true,maintainAspectRatio:false,indexAxis:'y',plugins:{legend:{display:false}},scales:{x:{beginAtZero:true}}}});}
  function renderTopLocations(rows){var map={};rows.forEach(function(d){var l=d.location||'ไม่ระบุ';if(!map[l])map[l]={location:l,total:0,c:countStatus([])};map[l].total++;map[l].c[d.status]++;});var list=Object.keys(map).map(function(k){return map[k];}).sort(function(a,b){return b.total-a.total;}).slice(0,12);text('sdLocationCount',Object.keys(map).length+' locations');html('sdTopLocationTable',list.length?'<div class="csv5-table-wrap"><table class="csv5-table"><thead><tr><th>Location</th><th>Total</th><th>พร้อมส่ง</th><th>รอสอบเทียบ</th><th>เช่ายืม</th></tr></thead><tbody>'+list.map(function(x){return'<tr><td><b>'+esc(x.location)+'</b></td><td>'+x.total+'</td><td>'+x.c['พร้อมส่ง']+'</td><td>'+x.c['รอสอบเทียบ']+'</td><td>'+x.c['เช่ายืม']+'</td></tr>';}).join('')+'</tbody></table></div>':'<div class="sp-muted">No location data</div>');}
  function renderContracts(rows){var map={};rows.filter(function(d){return d.status==='เช่ายืม';}).forEach(function(d){var l=d.location||'ไม่ระบุ';if(!map[l])map[l]={location:l,total:0,overdue:0,models:{},due:''};map[l].total++;if(d.isOverdue)map[l].overdue++;map[l].models[d.model]=(map[l].models[d.model]||0)+1;if(!map[l].due&&d.expectedReturn)map[l].due=d.expectedReturn;});var list=Object.keys(map).map(function(k){return map[k];}).sort(function(a,b){return b.overdue-a.overdue||b.total-a.total;});text('sdContractCount',list.length+' locations');html('sdContractTable',list.length?'<div class="csv5-table-wrap"><table class="csv5-table"><thead><tr><th>Location</th><th>Items</th><th>Models</th><th>Due Date</th><th>Alert</th></tr></thead><tbody>'+list.map(function(x){var models=Object.keys(x.models).map(function(m){return m+' ×'+x.models[m];}).join(', ');return'<tr><td><b>'+esc(x.location)+'</b></td><td>'+x.total+'</td><td>'+esc(models)+'</td><td>'+fmtDate(x.due)+'</td><td>'+(x.overdue?'<span class="csv5-contract-note">เกินกำหนด '+x.overdue+' เครื่อง</span>':'<span class="csv5-status csv5-rental">ใช้งานอยู่</span>')+'</td></tr>';}).join('')+'</tbody></table></div>':'<div class="sp-muted">ไม่มีรายการเช่ายืม</div>');}
  window.sd_openAlertPopup=function(){var rows=CSV6.alerts||[];var content=rows.length?'<div class="csv5-table-wrap" style="max-height:440px"><table class="csv5-table"><thead><tr><th>ID</th><th>Model</th><th>Location</th><th>Status</th><th>Action</th></tr></thead><tbody>'+rows.map(function(d){return'<tr><td><b>'+esc(d.idCode)+'</b></td><td>'+esc(d.model)+'</td><td>'+esc(d.location)+'</td><td>'+badge(d.status)+'</td><td>'+esc(d.actionRequired)+'</td></tr>';}).join('')+'</tbody></table></div>':'<div class="sp-muted">ไม่มี Alert</div>';if(window.Swal)Swal.fire({title:'Stock Alerts',width:1000,html:content,confirmButtonText:'Close'});};
